941	\section{Basic-open cover infrastructure}
942	\label{sec:basic_open_infrastructure}
943	
944	This section packages the standard basic-open cover of an affine open into the project's conventions. Given a subset $s \subseteq \mathcal O_X(U)$ spanning the unit ideal, the basic opens $D(f)$ for $f \in s$ form a cover of $U$. All members and their finite intersections are again affine.
945	
946	\begin{definition}[Basic-open cover]
947	  \label{def:Scheme_basicOpenCover}
948	  \lean{AlgebraicGeometry.Scheme.basicOpenCover}
949	  Let $U$ be an open of $X$ and $s \subseteq \mathcal O_X(U)$. The basic-open cover indexed by $s$ sends $f \in s$ to $D(f)$.
950	\end{definition}
951	
952	\begin{theorem}[Supremum equality]
953	  \label{thm:Scheme_basicOpenCover_supr_of_span_eq_top}
954	  \lean{AlgebraicGeometry.Scheme.basicOpenCover_supr_of_span_eq_top}
955	  \uses{def:Scheme_basicOpenCover}
956	  If $U$ is affine and $s$ spans the unit ideal, then $\bigsqcup_{f \in s} D(f) = U$.
957	\end{theorem}
958	
959	\begin{proof}
960	
961	
962	  Standard characterisation: the union of basic opens equals the whole affine if and only if the generators span the unit ideal.
