1102	  \[
1103	    \prod_{\alpha \in A} M_\alpha \longrightarrow \prod_{\beta \in B} M_{f(\beta)}
1104	  \]
1105	  admits a section, hence is a split epimorphism in the category of $k$-modules.
1106	\end{definition}
1107	
1108	\begin{proof}
1109	
1110	
1111	  Choose a retraction of $f$ (possible because $B$ injects into $A$), extend families on $B$ to families on $A$ by the chosen values on the complement, and verify the section identity pointwise.
1112	\end{proof}
1113	
1114	\begin{theorem}[From exactness of cochains to vanishing of Čech cohomology]
1115	  \label{thm:Scheme_cechCohomology_subsingleton_of_cechCochain_exactAt}
1116	  \lean{AlgebraicGeometry.Scheme.cechCohomology_subsingleton_of_cechCochain_exactAt}
1117	  Let $\mathcal F$ be a sheaf of $k$-modules on a $k$-scheme $X$, let $\mathfrak U = \{\mathcal U_i\}$ be an open cover, and let $n \ge 1$. If the Čech cochain complex of $\mathcal F$ with respect to $\mathfrak U$ is exact at degree $n$, then the Čech cohomology group $\check H^n(\mathfrak U, \mathcal F)$ is a subsingleton.
1118	\end{theorem}
1119	
1120	\begin{proof}
1121	
1122	
1123	  Exactness at degree $n$ means that the $n$-cocycles equal the $n$-coboundaries, so the quotient $\check H^n$ has at most one element.
1124	\end{proof}
1125	
1126	\begin{theorem}[Čech acyclicity for the structure sheaf]
1127	  \label{thm:basicOpenCover_isCechAcyclicCover_toModuleKSheaf}
1128	  \lean{AlgebraicGeometry.Scheme.basicOpenCover_isCechAcyclicCover_toModuleKSheaf}
1129	  \uses{def:Scheme_basicOpenCover, def:Scheme_IsCechAcyclicCover, thm:Scheme_basicOpenCover_finset_inf_eq_basicOpen_prod, thm:Scheme_basicOpenCover_finset_inf_le, thm:Scheme_basicOpenCover_finset_inf_isLocalization, thm:Scheme_cechCohomology_subsingleton_of_cechCochain_exactAt, def:Scheme_splitEpi_pi_lift_of_injective}
1130	  The Čech cohomology $\check H^n(\mathfrak U, \mathcal O_X)$ vanishes for every $n \ge 1$.
1131	\end{theorem}
1132	
1133	\begin{proof}
1134	  \uses{thm:Scheme_basicOpenCover_finset_inf_isLocalization, def:Scheme_IsCechAcyclicCover, thm:Scheme_cechCohomology_subsingleton_of_cechCochain_exactAt, def:Scheme_splitEpi_pi_lift_of_injective}
1135	  The classical proof proceeds in four steps.
1136	
1137	  \textbf{Step~1: Reduction to per-generator local exactness.} Since $s$ generates the unit ideal, exactness of a map of $\mathcal O_X(U)$-modules is a local property at the cover $\{D(f)\}_{f \in s}$. It suffices to prove exactness after localizing at each generator $f \in s$.
1138	
1139	  \textbf{Step~2: Identification of the localized complex.} Localizing at $f$ identifies the factor at $(f_0,\dots,f_n)$ with $\mathcal O_X(U)[1/(f f_0 \cdots f_n)]$. Reassembling, the localized Čech complex is naturally isomorphic to the Čech complex of $D(f)$ with respect to the restricted cover $\{D(f) \cap D(f')\}_{f' \in s}$. Concretely, the formalisation of this step uses four Mathlib API pieces in sequence. Writing $V_x = \bigcap_{a} D(x_a)$ for a tuple $x : \{0,\dots,n\} \to s_0$:
1140	  \begin{enumerate}
1141	    \item[(i)] \emph{Image-Finset bridge.} The categorical product $\prod^c_a D(x_a)$ in the lattice of opens coincides with the $\inf'$ of $D$ along the image $x(\{0,\dots,n\}) \subseteq s_0$. Mathlib's \texttt{Finset.inf\_univ\_eq\_iInf}, \texttt{Finset.inf'\_eq\_inf}, and \texttt{Finset.inf'\_image}, framed by a \texttt{le\_antisymm} step using the projection \texttt{Pi.\!$\pi$} and the canonical lift \texttt{Pi.lift}, identify these. (The direct route via a \texttt{CompleteLattice.finite\_product\_eq\_finset\_inf} fails on universe grounds: the index type $\mathrm{Fin}(n+1) : \mathrm{Type}_0$ and the open-set type $\mathrm{Opens} : \mathrm{Type}_u$ are not in the same universe.)
1142	    \item[(ii)] \emph{Restriction-of-section identity.} $V_x \cap D(f) = D(f|_{V_x})$, where $f|_{V_x}$ denotes the image of $f$ under the presheaf restriction $\mathcal O_X(U) \to \mathcal O_X(V_x)$. This is Mathlib's \texttt{Scheme.basicOpen\_res}.
1143	    \item[(iii)] \emph{Per-coord \texttt{IsLocalization.Away}.} Each $V_x$ is affine by (i) combined with Theorem~\ref{thm:Scheme_basicOpenCover_finset_inf_isAffineOpen}. Composing (i)–(ii) with \texttt{IsAffineOpen.isLocalization\_of\_eq\_basicOpen} then certifies
1144	    \[
1145	      \mathcal O_X(V_x \cap D(f)) \;=\; \mathcal O_X(V_x)\bigl[1/(f|_{V_x})\bigr]
1146	    \]
1147	    as an \texttt{IsLocalization.Away} algebra structure, with algebra map the presheaf restriction $\mathcal O_X(V_x) \to \mathcal O_X(V_x \cap D(f))$. Compare also Theorem~\ref{thm:Scheme_basicOpenCover_finset_inf_isLocalization} for the ambient $\inf'$-form.
1148	    \item[(iv)] \emph{Finite-product localization lift.} The per-coord \texttt{IsLocalization.Away} structures of (iii) are upgraded to \texttt{IsLocalizedModule} instances via the adapter
1149	    \texttt{instIsLocalizedModuleTo\-LinearMap\-To\-AlgHom\-Of\-IsLocalization\-AlgebraMap\-Submonoid} (in \textsf{Mathlib.Algebra.Module.LocalizedModule.IsLocalization}). The finite-product packaging \texttt{IsLocalizedModule.pi} (in \textsf{Mathlib.RingTheory.TensorProduct.IsBaseChangePi}), with \texttt{IsLocalizedModule.prodMap} furnishing the binary-product specialisation, then assembles these into a single \texttt{IsLocalizedModule\,(Submonoid.powers $f$)} instance on the cochain-degree product $\prod_x \mathcal O_X(V_x)$.
1150	  \end{enumerate}
1151	  With (i)–(iv) in hand, the $K_0$-level exactness $h_{a_0\text{-fun}}(f)$ established earlier transports along the two-row ladder built from \texttt{IsLocalizedModule.iso} on each summand $\mathrm{LocalizedModule}(\langle f \rangle)\,(K_0)_i \;\simeq_R\; M'_i$, where $M'_i$ is the slice-cover summand at degree $i$, via \texttt{Function.Exact.iff\_of\_ladder\_linearEquiv}. This yields the localized exactness at coordinate $f$ that Step~4 consumes. The split-epi reduction of Definition~\ref{def:Scheme_splitEpi_pi_lift_of_injective} enters at the cochain-degree-$0$ end of the ladder so that the augmented complex's $K_{-1}$-term threads through.
1152	
1153	  \textbf{Step~3: Contraction by extra degeneracy.} In the cover of $D(f)$, the member indexed by $f' = f$ is $D(f)$ itself. The augmented Čech complex therefore admits a section: map a family to its component at $f$. This section extends to an extra degeneracy on the augmented simplicial object, exhibiting the augmented Čech complex as contractible. Consequently the complex is exact in all positive degrees.
1154	
1155	  \textbf{Step~4: Globalization.} Each localized differential is exact, so the unlocalized differential is exact by the local-to-global principle for spanning sets. Hence $\check H^n(\mathfrak U, \mathcal O_X) = 0$ for $n \ge 1$.
1156	\end{proof}
1157	
1158	\begin{remark}[Finite-subspanning reduction]
1159	  \label{rem:basic_open_cech_finite_subspanning}
1160	  Although $s$ need not be finite, the unit ideal condition guarantees a finite subset $s_0 \subseteq s$ already generating the unit ideal. The two covers indexed by $s$ and $s_0$ induce the same sieve on $U$, so the refinement map is a quasi-isomorphism. It therefore suffices to prove acyclicity for a finite cover, which makes every cochain factor a finite product.
1161	\end{remark}
1162	
1163	\begin{remark}[Lean implementation]
1164	  The proof uses the local-to-global exactness theorem for spanning sets, the structure-sheaf-section-as-localization theorem for affine basic opens, exactness preservation under localization, and the extra-degeneracy contraction theorem for augmented simplicial objects. Mathlib does not currently host a formalisation of the Koszul complex or of the Čech-to-derived-functor spectral sequence; the proof above bypasses both by working directly with the augmented complex on each basic-open patch.
1165	\end{remark}
1166	
1167	\begin{remark}[Implementation status (iter-108 escape-valve)]
1168	  \label{rem:basicOpenCover_step2_status}
1169	  The Lean implementation of Step~2 lands inline at \texttt{AlgebraicJacobian/Cohomology/BasicOpenCech.lean}, lines~$1781$–$1846$, inside the body of the per-generator block \texttt{h\_loc\_exact}. Substeps~(i)–(iii) of the Mathlib-API recipe above — the image-Finset bridge of substep~(i), the restriction-of-section identity $V_x \cap D(f) = D(f|_{V_x})$ of substep~(ii), and the per-coord \texttt{IsLocalization.Away} certificate via \texttt{IsAffineOpen.isLocalization\_of\_eq\_basicOpen} of substep~(iii) — are committed as inline \texttt{have}-declarations at lines~$1786$–$1834$, together with the auxiliary inclusion $V_x \subseteq U$ that feeds substep~(iii) (approximately fifty lines of inline scaffolding, accumulated across iter-108 and iter-109 partial scaffolding).
1170	
1171	  The trailing transport — substep~(iv) of the recipe (per-$x$ \texttt{Algebra} and \texttt{IsScalarTower} synthesis, the \texttt{IsLocalizedModule.pi} lift on the cochain-degree product, with \texttt{IsLocalizedModule.prodMap} furnishing the binary-product specialisation) together with the ladder-\texttt{LinearEquiv} transport of $h_{a_0\text{-fun}}(f)$ — is \emph{deferred at iter-108 (Archon canonical iter-108) as a budget deferral, not a Mathlib gap.} Mathlib at the project's pin \texttt{b80f227} already contains \texttt{IsLocalizedModule.Away}, \texttt{IsLocalizedModule.pi}, \texttt{IsLocalizedModule.prodMap}, and the algebra-map$\to$localized-module adapter \texttt{instIsLocalizedModuleTo\-LinearMap\-To\-AlgHom\-Of\-IsLocalization\-AlgebraMap\-Submonoid}; the lemma is mechanizable from these pieces. The mechanization was deferred at iter-108 because the per-$x$ typeclass plumbing (in particular, threading \texttt{letI \dots in $\langle$goal-type$\rangle$} through the Lean elaborator) is eager rather than body-binder-introducing, so the per-$x$ algebra setup has no surviving binder to attach to; rewriting the block to introduce the typeclasses via a body-level \texttt{let} or a separate auxiliary lemma is a sizeable proof-engineering exercise that has been parked behind higher-priority Phase~B objectives and the C1 promotion of the refined \texttt{LineBundle} carrier. The corresponding inline \texttt{sorry} at \texttt{BasicOpenCech.lean:$1846$} is annotated with a budget-deferral marker (\texttt{DEFERRED (budget)}); it is not flagged as a \texttt{MATHLIB GAP}, and consequently does not enter the project's enumerated Mathlib-gap list. As of iter-112 that named-deferral surface comprises seven entries — \texttt{instIsMonoidal\_W} (varying-ring \texttt{stalk\_tensorObj} gap; \texttt{Modules/Monoidal.lean:$173$}), \texttt{cotangentExactSeq\_structure.h\_exact} (sheaf-of-modules exactness criterion; \texttt{Differentials.lean:$636$}), \texttt{serre\_duality\_gen