\section{Basic-open cover infrastructure}
\label{sec:basic_open_infrastructure}

This section packages the standard basic-open cover of an affine open into the project's conventions. Given a subset $s \subseteq \mathcal O_X(U)$ spanning the unit ideal, the basic opens $D(f)$ for $f \in s$ form a cover of $U$. All members and their finite intersections are again affine.

\begin{definition}[Basic-open cover]
  \label{def:Scheme_basicOpenCover}
  \lean{AlgebraicGeometry.Scheme.basicOpenCover}
  Let $U$ be an open of $X$ and $s \subseteq \mathcal O_X(U)$. The basic-open cover indexed by $s$ sends $f \in s$ to $D(f)$.
\end{definition}

\begin{theorem}[Supremum equality]
  \label{thm:Scheme_basicOpenCover_supr_of_span_eq_top}
  \lean{AlgebraicGeometry.Scheme.basicOpenCover_supr_of_span_eq_top}
  \uses{def:Scheme_basicOpenCover}
  If $U$ is affine and $s$ spans the unit ideal, then $\bigsqcup_{f \in s} D(f) = U$.
\end{theorem}

\begin{proof}


  Standard characterisation: the union of basic opens equals the whole affine if and only if the generators span the unit ideal.
\end{proof}

\begin{theorem}[Affine membership]
  \label{thm:Scheme_basicOpenCover_isAffineOpen}
  \lean{AlgebraicGeometry.Scheme.basicOpenCover_isAffineOpen}
  \uses{def:Scheme_basicOpenCover}
  If $U$ is affine, then every member $D(f)$ of the basic-open cover is affine.
\end{theorem}

\begin{proof}


  The basic open of an affine scheme is affine.
\end{proof}

\begin{theorem}[Existence producer from basic-open evidence]
  \label{thm:Scheme_hasAffineCechAcyclicCover_of_basicOpen}
  \lean{AlgebraicGeometry.Scheme.hasAffineCechAcyclicCover_of_basicOpen}
  \uses{def:Scheme_HasAffineCechAcyclicCover, def:Scheme_basicOpenCover, thm:Scheme_basicOpenCover_supr_of_span_eq_top}
  If for every affine open $U$ there exists a spanning subset $s \subseteq \mathcal O_X(U)$ such that the basic-open cover by $s$ is Čech-acyclic and carries a comparison isomorphism, then $\HasAffineCechAcyclicCover$ holds.
\end{theorem}

\begin{proof}


  Bundle the basic-open cover together with the supremum equality into the existential shape required by the carrier.
\end{proof}

\begin{theorem}[Curve specialisation]
  \label{thm:Scheme_hasAffineCechAcyclicCover_of_basicOpen_curve}
  \lean{AlgebraicGeometry.Scheme.hasAffineCechAcyclicCover_of_basicOpen_curve}
  \uses{thm:Scheme_hasAffineCechAcyclicCover_of_basicOpen}
  Same statement specialised to the structure sheaf $\mathcal O_C$.
\end{theorem}

\begin{proof}


  Direct application.
\end{proof}

\subsection{Intersection helpers}

Finite intersections of basic opens are again basic opens of a product.

\begin{theorem}[Pairwise intersection]
  \label{thm:Scheme_basicOpenCover_inter_eq_basicOpen_mul}
  \lean{AlgebraicGeometry.Scheme.basicOpenCover_inter_eq_basicOpen_mul}
  \uses{def:Scheme_basicOpenCover}
  For $f, g \in s$, $D(f) \cap D(g) = D(fg)$.
\end{theorem}

\begin{proof}


  Standard identity for basic opens.
\end{proof}

\begin{theorem}[Pairwise intersection is affine]
  \label{thm:Scheme_basicOpenCover_inter_isAffineOpen}
  \lean{AlgebraicGeometry.Scheme.basicOpenCover_inter_isAffineOpen}
  \uses{def:Scheme_basicOpenCover, thm:Scheme_basicOpenCover_inter_eq_basicOpen_mul}
  If $U$ is affine, then $D(f) \cap D(g)$ is affine.
\end{theorem}

\begin{proof}


  By the previous theorem it is a single basic open.
\end{proof}

\begin{theorem}[$n$-ary intersection]
  \label{thm:Scheme_basicOpenCover_finset_inf_eq_basicOpen_prod}
  \lean{AlgebraicGeometry.Scheme.basicOpenCover_finset_inf'_eq_basicOpen_prod}
  \uses{def:Scheme_basicOpenCover}
  For a non-empty finite subset $t \subseteq s$,
  \[
    \bigcap_{f \in t} D(f) \;=\; D\Bigl(\prod_{f \in t} f\Bigr).
  \]
\end{theorem}

\begin{proof}


  By induction on the finite subset, using the binary case.
\end{proof}

\begin{theorem}[$n$-ary intersection is affine]
  \label{thm:Scheme_basicOpenCover_finset_inf_isAffineOpen}
  \lean{AlgebraicGeometry.Scheme.basicOpenCover_finset_inf'_isAffineOpen}
  \uses{def:Scheme_basicOpenCover, thm:Scheme_basicOpenCover_finset_inf_eq_basicOpen_prod}
  If $U$ is affine, then $\bigcap_{f \in t} D(f)$ is affine.
\end{theorem>

\begin{proof}


  By the previous theorem it is a single basic open.
\end{proof}

